    string smallestNumber(string pattern) {
        string res = "";
        int inc = 1, dec = 9;
        for (char c : pattern) {
            if (c == 'I') {
                res += to_string(inc++);
            } else {
                res += to_string(dec--);
            }
        }
        return res;
    }
};```
